INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (1745, 197497, 9, 164, '一些看法', '通过近几场的替补生涯，有一些个人的看法需要发表：
<br>我们球队在比赛的前70分钟里面基本上和对手势均力敌，但是这种势均力敌是建立在我们的来回奔跑的基础之上的，当我们的体力透支的时候，我们在配合上的劣势就充分表现出来了，而对手在这个时候就能够很从容地进行倒脚配合。鉴于我们球队的体能情况并不理想，我认为球队在接下来的两场比赛中应该打得更加聪明一些，具体表现在：前锋线不要一拿球就要往前冲，毕竟打比赛的队伍并不像平时热身的队伍，后卫比较有经验！让我方前锋连续突破的几率比较小。前锋可以拿一下球或者回敲一下，等待我方的前卫线到位后在继续进攻（毕竟我方的前卫体能状况也不是很理想），这样做，既能保证我们的控球权，进攻的效率也会大大提高，体力也能达到合理的分配，不然球很快就丢了，前卫刚要压上又要回防，体力很能保证！！', '通过近几场的替补生涯，有一些个人的看法需要发表：

我们球队在比赛的前70分钟里面基本上和对手势均力敌，但是这种势均力敌是建立在我们的来回奔跑的基础之上的，当我们的体力透支的时候，我们在配合上的劣势就充分表现出来了，而对手在这个时候就能够很从容地进行倒脚配合。鉴于我们球队的体能情况并不理想，我认为球队在接下来的两场比赛中应该打得更加聪明一些，具体表现在：前锋线不要一拿球就要往前冲，毕竟打比赛的队伍并不像平时热身的队伍，后卫比较有经验！让我方前锋连续突破的几率比较小。前锋可以拿一下球或者回敲一下，等待我方的前卫线到位后在继续进攻（毕竟我方的前卫体能状况也不是很理想），这样做，既能保证我们的控球权，进攻的效率也会大大提高，体力也能达到合理的分配，不然球很快就丢了，前卫刚要压上又要回防，体力很能保证！！', NULL, '2003-03-03 10:51:00', 13, '20030425045732_bbsid_197497_board_9_38d77a4663.html', '20030425045732');
